import React, { useContext } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { AuthContext } from './App';
import { TEAMS } from './config';
import { motion, AnimatePresence } from 'framer-motion';

const NAV = [
  { path: '/dashboard', icon: 'home', label: 'Home' },
  { path: '/events', icon: 'auto_awesome', label: 'Events' },
  { path: '/prelim', icon: 'description', label: 'Screening' },
];

export default function Sidebar() {
  const { user, logout, openProfileModal } = useContext(AuthContext);
  const navigate = useNavigate();
  const { pathname } = useLocation();
  const teamInfo = user?.team ? TEAMS[user.team] : null;

  const houseColor = teamInfo?.colors.secondary || '#c9a84c';

  return (
    <aside className="fixed top-0 left-0 bottom-0 w-[240px] z-[200] hidden md:flex flex-col bg-gradient-to-b from-obsidian/95 to-midnight-blue/95 border-r border-ethereal-gold/20 backdrop-blur-2xl overflow-hidden shadow-2xl">
      {/* Decorative Shimmer Line */}
      <div className="absolute top-0 right-0 w-[1px] h-full bg-gradient-to-b from-transparent via-ethereal-gold/50 to-transparent pointer-events-none" />

      {/* Brand Header */}
      <div className="px-5 py-4 border-b border-white/5 flex justify-center items-center h-[72px]">
        <img
          src="/assets/images/hero_title.png"
          alt="ECMEET'26"
          className="w-full h-full object-contain drop-shadow-[0_0_12px_rgba(201,168,76,0.3)]"
        />
      </div>

      {/* User Profile */}
      {user && (
        <div 
          className="p-5 border-b border-white/5 flex items-center gap-3 cursor-pointer transition-all duration-300 hover:bg-ethereal-gold/5 group" 
          onClick={openProfileModal} 
          title="Edit Profile"
        >
          {user.profilePicture ? (
            <img 
              src={user.profilePicture} 
              alt="" 
              className="w-10 h-10 rounded-full object-cover border border-ethereal-gold/40 flex-shrink-0 group-hover:scale-110 transition-transform duration-300 shadow-[0_0_12px_rgba(201,168,76,0.3)]" 
              style={{ borderColor: `${houseColor}80` }}
            />
          ) : (
            <div className="w-10 h-10 rounded-full bg-ethereal-gold/10 border border-ethereal-gold/40 flex items-center justify-center font-cinzel text-ethereal-gold flex-shrink-0 group-hover:scale-110 transition-transform duration-300">
              {user.name?.[0]}
            </div>
          )}
          <div className="min-w-0">
            <div className="font-cinzel text-xs text-ethereal-gold-light tracking-wide leading-tight truncate group-hover:text-white transition-colors">
              {user.name}
            </div>
            {user?.houseRevealed && user?.team && pathname !== '/reveal' && (
              <span 
                className="inline-block mt-1 font-cinzel text-[10px] tracking-widest uppercase px-2 py-0.5 border opacity-80 rounded shadow-sm"
                style={{ color: houseColor, borderColor: `${houseColor}60` }}
              >
                {user.team}
              </span>
            )}
          </div>
        </div>
      )}

      {/* Navigation Links */}
      <nav className="flex-1 py-4 overflow-y-auto">
        <div className="font-cinzel text-[10px] tracking-[0.2em] text-ethereal-gold/60 uppercase px-5 pb-2">
          Navigation
        </div>
        
        {NAV.map(n => {
          const disabled = !user?.houseRevealed && n.path !== '/dashboard';
          const isActive = pathname === n.path;
          
          return (
            <button
              key={n.path}
              className={`w-full relative flex items-center gap-3 px-5 py-3 font-cinzel text-xs tracking-widest uppercase transition-all duration-300 border-none bg-transparent cursor-pointer text-left
                ${disabled ? 'opacity-30 cursor-not-allowed' : 'hover:bg-ethereal-gold/10'}
                ${isActive ? 'text-ethereal-gold-light bg-ethereal-gold/10' : 'text-ethereal-gold-light/60'}
              `}
              onClick={() => !disabled && navigate(n.path)}
              disabled={disabled}
              style={isActive ? { color: houseColor, textShadow: `0 0 10px ${houseColor}50` } : {}}
            >
              {isActive && (
                <motion.div 
                  layoutId="activeNav"
                  className="absolute left-0 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-ethereal-gold to-transparent" 
                  style={{ backgroundImage: `linear-gradient(180deg, transparent, ${houseColor}, transparent)` }}
                />
              )}
              
              <span className="material-symbols-outlined text-[1.1rem] shrink-0" style={{ fontVariationSettings: isActive ? "'FILL' 1" : "'FILL' 0" }}>
                {n.icon}
              </span>
              <span>{n.label}</span>
              
              {isActive && (
                <div className="ml-auto w-1.5 h-1.5 rounded-full" style={{ background: houseColor, boxShadow: `0 0 6px ${houseColor}` }} />
              )}
            </button>
          );
        })}
      </nav>

      {/* Decorative Footer Badge */}
      <div className="p-5 flex justify-center mt-auto">
        <div className="w-16 h-16 rounded-full p-[2px] bg-gradient-to-br from-ethereal-gold to-midnight-blue shadow-[0_0_15px_rgba(201,168,76,0.2)] group cursor-pointer hover:shadow-[0_0_25px_rgba(201,168,76,0.4)] transition-shadow duration-300">
          <img
            src="/assets/images/ecmeet_logo.jpeg"
            alt="ECMEET"
            className="w-full h-full object-cover rounded-full block"
          />
        </div>
      </div>

      {/* Logout Button */}
      <div className="p-5 border-t border-white/5">
        <button 
          className="w-full flex items-center gap-2.5 font-cinzel text-[11px] tracking-[0.12em] uppercase text-ethereal-gold-light/60 bg-transparent border-none py-2 cursor-pointer hover:text-red-400 transition-colors duration-200"
          onClick={logout}
        >
          <span className="material-symbols-outlined text-base">logout</span>
          Sign Out
        </button>
      </div>
    </aside>
  );
}
