import React, { useMemo } from 'react';
import { motion } from 'framer-motion';

export default function Particles() {
  const embers = useMemo(() =>
    Array.from({ length: 40 }, (_, i) => ({
      id: i,
      xOffset: Math.random() * 100, // percentage horizontal
      yDuration: Math.random() * 15 + 10, // vertical drift duration
      xDuration: Math.random() * 8 + 4, // horizontal sway
      size: Math.random() * 3 + 1, // pixel size
      delay: Math.random() * 10,
      opacity: Math.random() * 0.5 + 0.1,
      swayAmount: (Math.random() - 0.5) * 50, // horizontal drift
    }))
  , []);

  return (
    <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden mix-blend-screen">
      {embers.map((p) => (
        <motion.div
          key={p.id}
          initial={{ 
            y: '110vh', 
            x: `${p.xOffset}vw`, 
            opacity: 0 
          }}
          animate={{
            y: '-10vh',
            x: [`${p.xOffset}vw`, `${p.xOffset + p.swayAmount / 10}vw`, `${p.xOffset - p.swayAmount / 10}vw`],
            opacity: [0, p.opacity, p.opacity * 0.5, 0],
          }}
          transition={{
            y: { duration: p.yDuration, delay: p.delay, repeat: Infinity, ease: 'linear' },
            x: { duration: p.xDuration, delay: p.delay, repeat: Infinity, repeatType: 'mirror', ease: 'easeInOut' },
            opacity: { duration: p.yDuration, delay: p.delay, repeat: Infinity, times: [0, 0.2, 0.8, 1], ease: 'linear' }
          }}
          style={{
            width: p.size,
            height: p.size,
          }}
          className="absolute rounded-full bg-ethereal-gold shadow-[0_0_10px_rgba(201,168,76,0.8)]"
        />
      ))}
    </div>
  );
}
