import React, { useContext } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { AuthContext } from './App';

const NAV = [
  { path: '/dashboard', icon: 'home',          label: 'Home'      },
  { path: '/events',    icon: 'auto_awesome',   label: 'Events'    },
  { path: '/prelim',    icon: 'description',    label: 'Screening' },
];

export default function BottomNavbar() {
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();
  const { pathname } = useLocation();

  return (
    <nav className="fixed bottom-0 left-0 right-0 h-[68px] z-[200] bg-obsidian/90 border-t border-ethereal-gold/20 backdrop-blur-xl flex md:hidden items-center justify-around pb-safe">
      {NAV.map(n => {
        const disabled = !user?.houseRevealed && n.path !== '/dashboard';
        const isActive = pathname === n.path;
        
        return (
          <button
            key={n.path}
            className={`flex flex-col items-center gap-1 bg-transparent border-none py-2 px-4 transition-all duration-300 flex-1 relative
              ${disabled ? 'opacity-30 cursor-not-allowed' : 'cursor-pointer hover:text-ethereal-gold'}
              ${isActive ? 'text-ethereal-gold drop-shadow-lumos' : 'text-ethereal-gold-light/50'}
            `}
            onClick={() => !disabled && navigate(n.path)}
            disabled={disabled}
          >
            <span 
              className="material-symbols-outlined text-[1.4rem]"
              style={{ fontVariationSettings: isActive ? "'FILL' 1" : "'FILL' 0" }}
            >
              {n.icon}
            </span>
            <span className="font-cinzel text-[10px] tracking-widest uppercase">
              {n.label}
            </span>
            {isActive && (
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-[2px] bg-ethereal-gold rounded-full shadow-lumos" />
            )}
          </button>
        );
      })}
    </nav>
  );
}
