import React, { useContext, useState, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { AuthContext } from './App';
import { TEAMS } from './config';
import { motion, AnimatePresence } from 'framer-motion';

const PAGE_TITLES = {
  '/dashboard': 'Great Hall',
  '/events': 'Event Spellbook',
  '/prelim': 'Preliminary Screening',
  '/reveal': 'Sorting Ceremony',
};

export default function Topbar() {
  const { user, logout, openProfileModal } = useContext(AuthContext);
  const { pathname } = useLocation();
  const dropdownRef = useRef(null);
  const [showDropdown, setShowDropdown] = useState(false);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setShowDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const teamInfo = user?.team ? TEAMS[user.team] : null;
  const houseColor = teamInfo?.colors.secondary || '#c9a84c';
  const title = PAGE_TITLES[pathname] || 'ECMEET\'26';

  return (
    <div className="fixed top-3 right-4 left-4 md:left-[256px] md:right-auto md:w-auto h-[60px] md:h-[48px] z-[100] flex items-center justify-between md:justify-start px-5 bg-midnight-blue/70 backdrop-blur-xl border border-ethereal-gold/30 rounded-xl shadow-[0_4px_24px_rgba(0,0,0,0.4),0_0_0_1px_rgba(201,168,76,0.15)] transition-all duration-300">
      <div className="flex items-center gap-3">
        {/* Mobile only: brand image */}
        <img
          src="/assets/images/hero_title.png"
          alt="ECMEET'26"
          className="h-[46px] w-auto object-contain block md:hidden"
        />
        <span className="hidden md:block font-cinzel text-sm tracking-[0.18em] uppercase text-ethereal-gold drop-shadow-[0_0_12px_rgba(201,168,76,0.5)]">
          {title}
        </span>
      </div>

      <div className="flex justify-end items-center gap-3 md:hidden">
        {user?.houseRevealed && user?.team && pathname !== '/reveal' && (
          <span 
            className="flex items-center gap-1 font-cinzel text-[0.6rem] tracking-[0.15em] uppercase px-2 py-1 rounded-sm bg-white/5"
            style={{ color: houseColor, border: `1px solid ${houseColor}50`, boxShadow: `0 0 10px ${houseColor}20` }}
          >
            <span className="material-symbols-outlined text-[0.85rem]">shield</span>
            {user.team}
          </span>
        )}
        
        {user?.profilePicture && (
          <div className="relative flex" ref={dropdownRef}>
            <button 
              onClick={() => setShowDropdown(!showDropdown)}
              className="bg-transparent border-none p-0 cursor-pointer flex rounded-full hover:scale-105 transition-transform duration-200"
            >
              <img
                src={user.profilePicture}
                alt=""
                className="w-[30px] h-[30px] rounded-full object-cover"
                style={{ border: `1px solid ${houseColor}60`, boxShadow: `0 0 8px ${houseColor}40` }}
              />
            </button>

            <AnimatePresence>
              {showDropdown && (
                <motion.div 
                  initial={{ opacity: 0, y: 10, scale: 0.95 }}
                  animate={{ opacity: 1, y: 0, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  transition={{ duration: 0.2 }}
                  className="absolute top-[calc(100%+12px)] right-0 bg-obsidian/95 backdrop-blur-xl rounded-xl p-2 min-w-[160px] shadow-[0_10px_40px_rgba(0,0,0,0.6),0_0_0_1px_rgba(201,168,76,0.2)] z-[1000]"
                  style={{ border: `1px solid ${houseColor}40` }}
                >
                  <div className="px-4 py-3 border-b border-white/5 mb-1">
                    <p className="m-0 text-xs text-white font-cinzel font-semibold truncate">{user.name}</p>
                    <p className="m-0 text-[10px] text-white/40 font-garamond">{user?.admin ? 'Headmaster' : 'Student Wizard'}</p>
                  </div>

                  <button 
                    onClick={() => { setShowDropdown(false); openProfileModal(); }}
                    className="w-full flex items-center gap-2 px-4 py-2 bg-transparent text-ethereal-gold font-cinzel text-[10px] tracking-widest rounded-lg cursor-pointer hover:bg-ethereal-gold/10 hover:pl-5 transition-all duration-200"
                  >
                    <span className="material-symbols-outlined text-base">edit</span>
                    Edit Profile
                  </button>
                  
                  <button 
                    onClick={() => { setShowDropdown(false); logout(); }}
                    className="w-full flex items-center gap-2 px-4 py-2 bg-transparent text-red-500 font-cinzel text-[10px] tracking-widest rounded-lg cursor-pointer hover:bg-red-500/10 hover:pl-5 transition-all duration-200"
                  >
                    <span className="material-symbols-outlined text-base">logout</span>
                    Sign Out
                  </button>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}
      </div>
    </div>
  );
}