import React, { useContext, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from './App';
import { eventsAPI } from './api';
import { TEAMS } from './config';
import { motion } from 'framer-motion';

export default function Dashboard() {
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();
  const [registrations, setRegistrations] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const teamInfo = user?.team ? TEAMS[user.team] : null;
  const hc = teamInfo?.colors.secondary || '#c9a84c';
  const hp = teamInfo?.colors.primary || '#1a1a1a';

  useEffect(() => {
    eventsAPI.myRegistrations()
      .then(r => setRegistrations(r.data.registrations || []))
      .catch(() => { })
      .finally(() => setLoading(false));
  }, []);

  if (!user) return null;

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.15 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 100, damping: 15 } }
  };

  return (
    <div className="flex-1 w-full max-w-6xl mx-auto pt-[80px] md:pt-[20px] pb-10 px-4 md:px-8">
      <motion.div 
        variants={containerVariants} 
        initial="hidden" 
        animate="show"
        className="flex flex-col gap-6 md:gap-10"
      >
        
        {/* Profile Identity Card (Overlapping architectural layout) */}
        <motion.div variants={itemVariants} className="relative w-full rounded-2xl p-[1px] bg-gradient-to-br from-ethereal-gold/30 to-midnight-blue/10 overflow-hidden shadow-lumos">
          <div className="relative w-full h-full bg-obsidian/95 backdrop-blur-2xl rounded-2xl p-6 md:p-10 overflow-hidden isolate" style={{ boxShadow: `inset 0 0 80px ${hp}20` }}>
            
            {/* Ambient Background Glow */}
            <div className="absolute inset-0 z-0 pointer-events-none opacity-40 mix-blend-screen" style={{ background: `radial-gradient(circle at 80% 50%, ${hp}, transparent 60%)` }} />

            {/* Faded House Emblem */}
            {user.team && (
              <img
                src={`/assets/homeimages/${user.team.toLowerCase()}.svg`}
                alt=""
                className="absolute top-1/2 -translate-y-1/2 -right-10 w-[300px] opacity-5 pointer-events-none -rotate-12 z-0"
                style={{ filter: `drop-shadow(0 0 30px ${hc})` }}
                onError={e => e.target.style.display = 'none'}
              />
            )}

            <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center gap-6 md:gap-10">
              
              {/* Avatar Stack */}
              <div className="relative shrink-0">
                <div className="w-24 h-24 rounded-full p-1 bg-gradient-to-br from-ethereal-gold to-midnight-blue drop-shadow-[0_0_20px_rgba(201,168,76,0.5)]">
                  {user.profilePicture ? (
                    <img src={user.profilePicture} alt="" className="w-full h-full rounded-full object-cover" />
                  ) : (
                    <div className="w-full h-full rounded-full bg-obsidian flex items-center justify-center font-cinzel text-3xl text-ethereal-gold">
                      {user.name?.[0]}
                    </div>
                  )}
                </div>
                {teamInfo && (
                  <img
                    src={`/assets/images/logos/${teamInfo.logo}`}
                    alt=""
                    className="absolute -bottom-2 -right-2 w-10 h-10 object-contain drop-shadow-md"
                    onError={e => e.target.style.display = 'none'}
                  />
                )}
              </div>

              {/* Informational Typographic Architecture */}
              <div className="flex-1 flex flex-col">
                <span className="font-cinzel text-[10px] tracking-[0.2em] text-ethereal-gold/60 uppercase mb-2">
                  Welcome back, Wizard
                </span>
                <h1 className="font-harry text-4xl md:text-5xl lg:text-6xl text-ethereal-gold drop-shadow-lumos mb-2 leading-none">
                  {user.name}
                </h1>
                <p className="font-garamond text-lg text-ethereal-gold-light/70 mb-4">
                  {user.email}
                </p>
                <div className="flex flex-wrap items-center gap-3">
                  <span 
                    className="flex items-center gap-1.5 font-cinzel text-xs tracking-widest uppercase px-3 py-1 bg-white/5 rounded border backdrop-blur-sm"
                    style={{ color: hc, borderColor: `${hc}40`, boxShadow: `0 0 15px ${hc}20` }}
                  >
                    <span className="material-symbols-outlined text-[1rem]">shield</span>
                    {user.team || 'Unsorted'}
                  </span>
                  {user.rrn && (
                    <span className="font-cinzel text-[10px] tracking-widest text-ethereal-gold-light/60 border border-ethereal-gold/20 px-3 py-1 rounded">
                      RRN: {user.rrn}
                    </span>
                  )}
                </div>
              </div>

              {/* Large Team Logo Desktop */}
              {teamInfo && (
                <div className="hidden md:block shrink-0 ml-auto grayscale-[20%] opacity-80 hover:grayscale-0 hover:opacity-100 transition-all duration-500 hover:scale-105">
                  <img
                    src={`/assets/images/logos/${teamInfo.logo}`}
                    alt={user.team}
                    className="w-28 h-28 object-contain"
                    style={{ filter: `drop-shadow(0 0 20px ${hc}40)` }}
                    onError={e => e.target.style.display = 'none'}
                  />
                </div>
              )}
            </div>

            {/* Academic Demographics Details */}
            {(user.department || user.section || user.contactNumber) && (
              <div className="relative z-10 mt-8 pt-8 border-t border-ethereal-gold/10 grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                  { icon: 'school', label: 'Department', value: user.department },
                  { icon: 'class', label: 'Class', value: user.class },
                  { icon: 'sort', label: 'Section', value: user.section },
                  { icon: 'call', label: 'Contact', value: user.contactNumber },
                ].filter(f => f.value).map(f => (
                  <div key={f.label} className="flex flex-col">
                    <span className="flex items-center gap-1.5 font-cinzel text-[9px] tracking-[0.15em] text-ethereal-gold/50 uppercase mb-1">
                      <span className="material-symbols-outlined text-[14px]">{f.icon}</span>
                      {f.label}
                    </span>
                    <span className="font-garamond text-lg text-ethereal-gold-light">
                      {f.value}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </motion.div>

        {/* Dashboard Actions Grid */}
        <motion.div variants={itemVariants} className="flex flex-col gap-4">
          <SectionTitle icon="auto_awesome" title="Magical Actions" />
          <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
            <ActionCard
              icon="celebration"
              title="Sorting Ceremony"
              desc={user.houseRevealed ? 'Replay the ceremony' : 'Discover your house'}
              disabled={false}
              hc={hc}
              onClick={() => navigate('/reveal')}
            />
            <ActionCard
              icon="auto_awesome"
              title="Register Spell"
              desc={`${registrations.length}/3 events registered`}
              hc={hc}
              badge={registrations.length > 0 ? String(registrations.length) : null}
              onClick={() => navigate('/events')}
            />
            <ActionCard
              icon="description"
              title="Preliminary Screen"
              desc="View screening info"
              hc={hc}
              onClick={() => navigate('/prelim')}
            />
          </div>
        </motion.div>

        {/* Lower Dash Content Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          
          {/* House Information Board */}
          {teamInfo && (
            <motion.div variants={itemVariants} className="flex flex-col gap-4">
               <SectionTitle icon="shield" title={`House ${user.team}`} />
               <div className="relative rounded-2xl p-6 bg-obsidian/80 border border-ethereal-gold/20 backdrop-blur-md overflow-hidden group hover:border-ethereal-gold/40 transition-colors duration-300 shadow-lumos">
                 <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-bl from-ethereal-gold/10 to-transparent blur-3xl pointer-events-none" style={{ backgroundImage: `linear-gradient(to bottom left, ${hc}20, transparent)` }} />
                 <p className="font-garamond italic text-xl text-ethereal-gold-light/90 mb-4 leading-relaxed group-hover:text-ethereal-gold-light transition-colors">
                   "{teamInfo.description}"
                 </p>
                 <div className="inline-flex font-cinzel text-xs tracking-[0.15em] text-ethereal-gold/80 bg-white/5 px-4 py-2 rounded border border-white/5">
                   <span className="mr-2 opacity-50">TRAITS:</span> {teamInfo.traits}
                 </div>
               </div>
            </motion.div>
          )}

          {/* Registrations List Scroll */}
          <motion.div variants={itemVariants} className="flex flex-col gap-4">
            <SectionTitle icon="how_to_reg" title="Registered Events" />
            <div className="flex flex-col gap-3">
              {!loading && registrations.length === 0 && (
                <div className="p-6 rounded-2xl bg-obsidian/40 border border-white/5 text-center font-garamond text-ethereal-gold-light/40 italic">
                  No events registered yet. Open the Event Spellbook to begin.
                </div>
              )}
              {registrations.map(r => (
                <motion.div 
                  whileHover={{ scale: 1.02 }}
                  key={r._id} 
                  className="flex items-center justify-between p-5 rounded-xl bg-obsidian/80 border border-ethereal-gold/20 backdrop-blur-md shadow-lg hover:border-ethereal-gold/50 cursor-pointer group"
                >
                  <div className="flex items-center gap-4">
                    <span className="material-symbols-outlined text-ethereal-gold text-2xl group-hover:drop-shadow-[0_0_8px_rgba(201,168,76,0.8)] transition-all">bookmark_star</span>
                    <div className="flex flex-col">
                      <p className="font-cinzel text-sm tracking-widest text-ethereal-gold-light uppercase">{r.eventName}</p>
                      <p className="font-garamond text-xs text-ethereal-gold-light/50">
                        {new Date(r.createdAt).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' })}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5 px-3 py-1 font-cinzel text-[9px] tracking-widest text-emerald-400 border border-emerald-400/40 bg-emerald-400/10 rounded uppercase">
                    <span className="material-symbols-outlined text-[14px]">check_circle</span>
                    Confirmed
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>

        </div>
      </motion.div>
    </div>
  );
}

// Helper Components

function SectionTitle({ icon, title }) {
  return (
    <div className="flex items-center gap-3 w-full">
      <span className="material-symbols-outlined text-ethereal-gold drop-shadow-[0_0_8px_rgba(201,168,76,0.5)]">{icon}</span>
      <h3 className="font-cinzel text-sm tracking-[0.2em] uppercase text-ethereal-gold drop-shadow-lumos truncate pb-1">
        {title}
      </h3>
      <div className="flex-1 h-[1px] bg-gradient-to-r from-ethereal-gold/30 to-transparent" />
    </div>
  );
}

function ActionCard({ icon, title, desc, disabled, onClick, hc, badge }) {
  return (
    <motion.div
      whileHover={!disabled ? { y: -5, scale: 1.02 } : {}}
      whileTap={!disabled ? { scale: 0.98 } : {}}
      onClick={!disabled ? onClick : undefined}
      className={`relative p-6 rounded-2xl bg-obsidian/80 border border-ethereal-gold/20 backdrop-blur-md overflow-hidden transition-colors duration-300 shadow-lg group
        ${disabled ? 'opacity-50 cursor-not-allowed grayscale' : 'cursor-pointer hover:border-ethereal-gold hover:shadow-[0_0_20px_rgba(201,168,76,0.2)] hover:bg-obsidian'}
      `}
    >
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-bl from-ethereal-gold/10 to-transparent blur-2xl pointer-events-none group-hover:from-ethereal-gold/20 transition-all duration-500" />
      
      {badge && (
        <div className="absolute top-4 right-4 bg-ethereal-gold text-obsidian font-cinzel font-bold text-[10px] px-2.5 py-1 rounded-full drop-shadow-md">
          {badge}
        </div>
      )}

      <span className="material-symbols-outlined text-4xl text-ethereal-gold mb-3 group-hover:drop-shadow-[0_0_12px_rgba(201,168,76,0.8)] transition-all duration-300">
        {icon}
      </span>
      
      <h4 className="font-cinzel text-sm tracking-widest text-ethereal-gold-light uppercase mb-1">
        {title}
      </h4>
      <p className="font-garamond text-xs text-ethereal-gold-light/60">
        {desc}
      </p>
    </motion.div>
  );
}
